import React from 'react'
import { Row, Col, Form, Button } from 'react-bootstrap'

function FormInputs({addQuestionAndAnswer}) {
    const [question, setQuestion] = useState('')
    const [answer, setAnswer] = useState('')
    const handleQuestionChange = (e) => {
        setQuestion(e.target.value)
    }
    const handleAnswerChange = (e) => {
        setAnswer(e.target.value)
    }
  return (
    <Row className='my-2'>
<Col sm="5">
<Form.Control onChange={handleQuestionChange} type="text" placeholder="اكتب سؤالك هنا ثم اضغط على إضافة" />
</Col>
<Col sm="5">

<Form.Control onChange={handleAnswerChange} type="text" placeholder="اكتب الإجابة هنا" />
</Col>
<Col sm="2">
      <button className='btn-color' onClick={addQuestionAndAnswer} type="submit">إضافة</button>
</Col>
    </Row>
  )
}

export default FormInputs
